INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '0cdcbaf3-294b-4ab4-9e65-c2c95f03c1eb', $$QUIZ-003$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Intervalos Musicais$$, $$Teste seu conhecimento sobre intervalos musicais.$$, $$Reconhecer intervalos musicais; Compreender distâncias entre notas$$, 2, 150, 'practical', '{"questoes": [{"opcoes": ["1 tom", "1,5 tons", "2 tons", "2,5 tons"], "correta": 2, "pergunta": "Quantos tons tem uma terça maior?", "explicacao": "Uma terça maior tem 2 tons (4 semitons). Exemplo: de Dó para Mi. A terça menor tem 1,5 tons (3 semitons)."}, {"opcoes": ["Terça", "Quarta", "Quinta", "Sexta"], "correta": 2, "pergunta": "Qual intervalo há entre Dó e Sol?", "explicacao": "De Dó a Sol temos uma quinta justa (5 notas: Dó, Ré, Mi, Fá, Sol). É um dos intervalos mais consonantes e importantes na música."}, {"opcoes": ["8", "10", "12", "14"], "correta": 2, "pergunta": "Uma oitava equivale a quantos semitons?", "explicacao": "Uma oitava tem 12 semitons. É a distância de uma nota até a mesma nota em outra altura (ex: de Dó a Dó). Representa a frequência dobrada."}], "aula_requisito": 4, "minimo_acertos": 2}'::jsonb, '[]', true, '2025-10-27 21:00:21.599587+00'::timestamptz, '2025-10-27 21:00:21.599587+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '10cfd6fb-82ca-4436-857a-5b1c6fb911a9', $$QUIZ-006$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Dinâmica e Expressão Musical$$, $$Sinais de dinâmica (piano, forte, crescendo), articulação e agógica.$$, NULL, 2, 150, 'theoretical', '{"questoes": [{"opcoes": ["Tocar devagar", "Tocar suave/baixo", "Tocar rápido", "Tocar forte"], "correta": 1, "pergunta": "O que significa \"piano\" (p) em uma partitura?", "explicacao": "Piano (p) significa tocar suave, com volume baixo. Não confunda com velocidade! \"Pianissimo\" (pp) é ainda mais suave."}, {"opcoes": ["Acelerar", "Aumentar volume gradualmente", "Tocar cada vez mais forte", "Pausa longa"], "correta": 1, "pergunta": "O que é um \"crescendo\"?", "explicacao": "Crescendo (<) significa aumentar o volume gradualmente ao longo da passagem. O símbolo parece uma abertura à direita."}, {"opcoes": ["Lento", "Piano", "Staccato", "Legato"], "correta": 1, "pergunta": "Qual é o oposto de \"forte\" (f)?", "explicacao": "Piano (p) é o oposto de forte (f). Piano = suave/baixo, Forte = alto/forte. São extremos opostos de dinâmica (volume)."}], "aula_requisito": 10, "minimo_acertos": 2}'::jsonb, '[]', true, '2025-10-28 01:00:50.854504+00'::timestamptz, '2025-10-28 01:00:50.854504+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '125c877f-e47d-48e0-9f11-27a711102978', $$QUIZ-008$$, '28ff3697-1df2-48a6-a961-2f10054a3720', $$História da Música - Períodos$$, $$Barroco, Clássico, Romântico: compositores, características e obras.$$, NULL, 3, 200, 'theoretical', '{"questoes": [{"opcoes": ["Clássico", "Romântico", "Renascimento", "Moderno"], "correta": 2, "pergunta": "Qual período vem ANTES do Barroco?", "explicacao": "A ordem cronológica é: Medieval → Renascimento → Barroco → Clássico → Romântico → Moderno. O Renascimento (séc. XV-XVI) vem antes do Barroco (séc. XVII-XVIII)."}, {"opcoes": ["Mozart", "Bach", "Beethoven", "Chopin"], "correta": 1, "pergunta": "Qual compositor é do período Barroco?", "explicacao": "Johann Sebastian Bach (1685-1750) é o maior representante do Barroco. Mozart e Beethoven são do Clássico, Chopin é do Romântico."}, {"opcoes": ["Música religiosa", "Formas rígidas", "Expressão emocional intensa", "Polifonia complexa"], "correta": 2, "pergunta": "Qual característica define o período Romântico?", "explicacao": "O Romantismo (séc. XIX) valoriza a expressão emocional, individualidade, nacionalismo e liberdade formal. Compositores: Chopin, Liszt, Wagner, Tchaikovsky."}, {"opcoes": ["Música muito ornamentada", "Equilíbrio e clareza", "Expressão extrema", "Música eletrônica"], "correta": 1, "pergunta": "O período Clássico é conhecido por:", "explicacao": "O Classicismo (séc. XVIII - Mozart, Haydn) busca equilíbrio, clareza, formas bem definidas (sonata, sinfonia). Contrasta com o Barroco ornamentado e o Romântico emocional."}, {"opcoes": ["50 anos", "100 anos", "150 anos", "200 anos"], "correta": 2, "pergunta": "Quantos anos durou aproximadamente o período Barroco?", "explicacao": "O Barroco durou aproximadamente 150 anos (1600-1750). Começa com Monteverdi e termina com a morte de Bach em 1750."}], "aula_requisito": 15, "minimo_acertos": 3}'::jsonb, '[]', true, '2025-10-28 01:00:50.854504+00'::timestamptz, '2025-10-28 01:00:50.854504+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '15a35af6-94df-4b20-a3f9-40cc22c23f46', $$QUIZ-009$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Classificação de Instrumentos$$, $$Famílias de instrumentos: cordas, sopros, percussão, teclados. Reconheça timbres!$$, NULL, 2, 150, 'theoretical', '{"questoes": [{"opcoes": ["Sopro", "Cordas", "Percussão", "Teclado"], "correta": 1, "pergunta": "A qual família pertence o violino?", "explicacao": "O violino pertence à família das cordas (cordas friccionadas com arco). Outros: viola, violoncelo, contrabaixo. Todos têm 4 cordas e são tocados com arco."}, {"opcoes": ["Flauta", "Trompete", "Violão", "Clarinete"], "correta": 2, "pergunta": "Qual NÃO é um instrumento de sopro?", "explicacao": "Violão é de cordas (cordas dedilhadas). Flauta, trompete e clarinete são de sopro. Sopros se dividem em: madeiras (flauta, clarinete) e metais (trompete, trombone)."}, {"opcoes": ["Têm cordas", "São soprados", "São percutidos ou sacudidos", "Têm teclas"], "correta": 2, "pergunta": "O que caracteriza os instrumentos de percussão?", "explicacao": "Percussão = instrumentos que produzem som ao serem batidos, sacudidos ou raspados. Exemplos: tambor, pandeiro, triângulo, xilofone, maracas."}, {"opcoes": ["Percussão", "Cordas", "Teclados", "Todas as anteriores"], "correta": 3, "pergunta": "O piano pertence a qual família?", "explicacao": "O piano é híbrido! Tem teclado (interface), cordas (fonte sonora) e produz som por percussão (martelos batem nas cordas). Pode ser classificado nas três famílias."}], "aula_requisito": 18, "minimo_acertos": 2}'::jsonb, '[]', true, '2025-10-28 01:00:50.854504+00'::timestamptz, '2025-10-28 01:00:50.854504+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '22f0a9f6-1cef-4ad0-ae4b-e131fc533571', $$ALPHA_2025$$, '28ff3697-1df2-48a6-a961-2f10054a3720', $$Desafio Alpha: Pioneiros da Música$$, $$Bem-vindo ao Desafio Alpha! Como um dos nossos primeiros usuários, você tem a oportunidade única de conquistar a badge lendária "Alpha Tester 🚀" e 500 pontos de experiência. Complete 5 tarefas essenciais e um desafio bonus para se tornar um verdadeiro pioneiro. Esta é uma oportunidade que nunca mais estará disponível!$$, $$Completar perfil com informações pessoais e preferências musicais; Assistir primeira aula completa do curso; Explorar pelo menos 5 instrumentos diferentes na biblioteca; Conhecer 3 compositores clássicos importantes; Completar um quiz com 70% de acerto ou mais; Compartilhar feedback para melhorar a plataforma$$, 3, 500, 'especial', '{"tarefas": [{"id": "tarefa_1", "nome": "Perfil Completo", "tipo": "perfil", "icone": "👤", "pontos": 100, "condicoes": {"nome_preenchido": true, "avatar_selecionado": true, "compositor_favorito_selecionado": true, "instrumento_preferido_selecionado": true}, "descricao": "Complete seu perfil com nome, avatar e preferências musicais", "obrigatoria": true}, {"id": "tarefa_2", "nome": "Primeira Aula", "tipo": "aula", "icone": "📚", "pontos": 100, "condicoes": {"aula_assistida": true, "tempo_minimo_visualizacao": 300}, "descricao": "Assista sua primeira aula completa em qualquer curso", "obrigatoria": true}, {"id": "tarefa_3", "nome": "Explorar Instrumentos", "tipo": "exploracao", "icone": "🎸", "pontos": 100, "condicoes": {"instrumentos_visitados": 5, "paginas_instrumentos_diferentes": true}, "descricao": "Visite a Biblioteca de Instrumentos e explore pelo menos 5 instrumentos diferentes", "obrigatoria": true}, {"id": "tarefa_4", "nome": "Conhecer Compositores", "tipo": "exploracao", "icone": "🎼", "pontos": 100, "condicoes": {"tempo_minimo_leitura": 120, "compositores_visitados": 3}, "descricao": "Explore a seção História da Música e leia sobre pelo menos 3 compositores diferentes", "obrigatoria": true}, {"id": "tarefa_5", "nome": "Quiz Musical", "tipo": "quiz", "icone": "🎯", "pontos": 100, "condicoes": {"quiz_completado": true, "percentual_minimo_acerto": 70}, "descricao": "Complete um quiz sobre história da música com pelo menos 70% de acerto", "obrigatoria": true}, {"id": "tarefa_bonus", "nome": "Feedback Alpha", "tipo": "feedback", "icone": "💬", "pontos": 100, "condicoes": {"feedback_enviado": true, "caracteres_minimos": 50}, "descricao": "Compartilhe sua experiência e sugestões para melhorarmos a plataforma", "obrigatoria": false}], "recompensas": {"pontos_xp": 500, "badge_lendaria": true, "titulo_especial": "Pioneiro Alpha", "pontos_bonus_possivel": 200}, "pontos_total_base": 500, "mensagem_conclusao": "🎉 Parabéns, Pioneiro! Você completou o Desafio Alpha e conquistou a badge lendária Alpha Tester! Esta conquista é permanente e exclusiva.", "pontos_tarefa_bonus": 100, "dias_bonus_velocidade": 7, "pontos_bonus_velocidade": 100}'::jsonb, '{"opcionais": ["Fones de ouvido para melhor experiência nas aulas", "Caderno para anotações"], "necessarios": ["Acesso à plataforma Nipo School", "Tempo estimado: 2-3 horas", "Conexão com internet", "Dispositivo compatível (desktop ou mobile)"]}'::jsonb, true, '2025-10-27 16:46:06.477193+00'::timestamptz, '2025-10-27 16:46:06.477193+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

