INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '45a0deb8-fe6d-4b90-b7cc-ab9c9f6d4950', $$QUIZ-001$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Teoria Musical Básica$$, $$Quiz sobre fundamentos da música: notas, claves, figuras rítmicas.$$, $$Identificar elementos básicos da notação musical; Reconhecer figuras rítmicas; Compreender a pauta musical$$, 1, 100, 'practical', '{"questoes": [{"opcoes": ["3", "4", "5", "6"], "correta": 2, "pergunta": "Quantas linhas tem uma pauta musical?", "explicacao": "Uma pauta musical tem 5 linhas e 4 espaços. As notas são escritas nas linhas e nos espaços, formando a base da notação musical ocidental."}, {"opcoes": ["Semibreve", "Mínima", "Semínima", "Colcheia"], "correta": 2, "pergunta": "Qual figura vale 1 tempo?", "explicacao": "A semínima vale 1 tempo (1 batida). A semibreve vale 4 tempos, a mínima 2 tempos, e a colcheia 1/2 tempo (meio tempo)."}, {"opcoes": ["5", "7", "8", "12"], "correta": 1, "pergunta": "Quantas notas musicais existem?", "explicacao": "Existem 7 notas musicais naturais: Dó, Ré, Mi, Fá, Sol, Lá e Si. Com os acidentes (sustenidos e bemóis), temos 12 semitons na escala cromática, mas apenas 7 notas naturais."}], "aula_requisito": 0, "minimo_acertos": 2, "tempo_limite_minutos": 15}'::jsonb, '[]', true, '2025-10-27 21:00:21.599587+00'::timestamptz, '2025-10-27 21:00:21.599587+00'::timestamptz)
