INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '4ef345f1-653d-4f42-ad12-474df6c8e86e', $$QUIZ-007$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Compassos e Fórmulas de Tempo$$, $$Identifique compassos binários, ternários e quaternários. Leia fórmulas de compasso!$$, NULL, 2, 150, 'theoretical', '{"questoes": [{"opcoes": ["4 tempos por compasso, semínima = 1 tempo", "4 compassos por música", "4 notas por compasso", "4 instrumentos"], "correta": 0, "pergunta": "O que significa a fórmula de compasso 4/4?", "explicacao": "4/4 significa: 4 tempos por compasso (número de cima) e a semínima vale 1 tempo (número de baixo = 4). É o compasso mais comum na música popular."}, {"opcoes": ["2 tempos", "3 tempos", "4 tempos", "6 tempos"], "correta": 1, "pergunta": "Quantos tempos tem um compasso 3/4?", "explicacao": "Compasso 3/4 tem 3 tempos por compasso. É o compasso característico da valsa. A semínima continua valendo 1 tempo."}, {"opcoes": ["Ternário", "Binário", "Quaternário", "Quinário"], "correta": 1, "pergunta": "Qual tipo de compasso é o 2/4?", "explicacao": "2/4 é binário (2 tempos por compasso). Comum em marchas e polcas. Binário = 2 tempos, Ternário = 3 tempos, Quaternário = 4 tempos."}, {"opcoes": ["Com duas claves", "Cada tempo se divide em 3", "Com pausas", "Com muitas notas"], "correta": 1, "pergunta": "O que é um compasso composto?", "explicacao": "No compasso composto, cada tempo se divide em 3 partes (ternário). Exemplo: 6/8 (2 tempos compostos). No simples, cada tempo se divide em 2."}], "aula_requisito": 12, "minimo_acertos": 2}'::jsonb, '[]', true, '2025-10-28 01:00:50.854504+00'::timestamptz, '2025-10-28 01:00:50.854504+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

