INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '62ee05c6-7c38-4f18-94ab-950b96471361', $$QUIZ-004$$, '8622a0d3-c389-47bf-a3a9-843bfcc293a2', $$Escalas Maiores$$, $$Identifique a estrutura das escalas maiores.$$, $$Compreender estrutura de escalas maiores; Identificar padrões de tons e semitons$$, 3, 200, 'mensal', '{"questoes": [{"opcoes": ["T-T-S-T-T-T-S", "T-S-T-T-S-T-T", "S-T-T-T-S-T-T", "T-T-T-S-T-T-S"], "correta": 0, "pergunta": "Qual é a fórmula de tons de uma escala maior?", "explicacao": "A escala maior segue: Tom-Tom-Semitom-Tom-Tom-Tom-Semitom (T-T-S-T-T-T-S). Esta fórmula pode ser aplicada a partir de qualquer nota."}, {"opcoes": ["Nenhum", "1 sustenido (Fá#)", "2 sustenidos", "3 sustenidos"], "correta": 1, "pergunta": "Quantos sustenidos tem a escala de Sol Maior?", "explicacao": "Sol Maior tem 1 sustenido: Fá#. A sequência é: Sol, Lá, Si, Dó, Ré, Mi, Fá#, Sol."}, {"opcoes": ["Sol Maior", "Ré Maior", "Dó Maior", "Fá Maior"], "correta": 2, "pergunta": "Qual escala maior não tem acidentes?", "explicacao": "Dó Maior é a única escala maior sem sustenidos ou bemóis: Dó, Ré, Mi, Fá, Sol, Lá, Si, Dó. Por isso é geralmente a primeira escala ensinada."}, {"opcoes": ["Decoração na partitura", "Sustenidos ou bemóis no início", "Tipo de clef", "Símbolo de tempo"], "correta": 1, "pergunta": "O que é uma armadura de clave?", "explicacao": "A armadura de clave são os sustenidos ou bemóis escritos logo após a clave, indicando a tonalidade da música (qual escala está sendo usada)."}], "aula_requisito": 6, "minimo_acertos": 3}'::jsonb, '[]', true, '2025-10-27 21:00:21.599587+00'::timestamptz, '2025-10-27 21:00:21.599587+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '62f312fa-39da-451e-a49b-d292b6e7b1da', $$QUIZ-005$$, '8622a0d3-c389-47bf-a3a9-843bfcc293a2', $$Acordes e Harmonia Básica$$, $$Tríades maiores, menores e formação de acordes.$$, $$Formar acordes básicos; Identificar tríades maiores e menores; Compreender harmonia$$, 3, 200, 'mensal', '{"questoes": [{"opcoes": ["2 notas", "3 notas", "4 notas", "5 notas"], "correta": 1, "pergunta": "Quantas notas formam uma tríade?", "explicacao": "Uma tríade é formada por 3 notas: fundamental, terça e quinta. É o acorde básico da harmonia tradicional."}, {"opcoes": ["A fundamental", "A terça", "A quinta", "A sétima"], "correta": 1, "pergunta": "O que torna um acorde maior ou menor?", "explicacao": "A terça define se o acorde é maior ou menor. Terça maior (2 tons) = acorde maior. Terça menor (1,5 tons) = acorde menor."}, {"opcoes": ["Dó-Ré-Mi", "Dó-Mi-Sol", "Dó-Fá-Sol", "Dó-Mi-Lá"], "correta": 1, "pergunta": "Quais são as notas do acorde de Dó Maior?", "explicacao": "Dó Maior = Dó (fundamental) + Mi (terça maior) + Sol (quinta justa). Estas três notas formam a tríade de Dó Maior."}, {"opcoes": ["Tocar ao contrário", "Mudar a nota mais grave", "Acorde em outra oitava", "Acorde sustenido"], "correta": 1, "pergunta": "O que significa \"inversão de acorde\"?", "explicacao": "Inversão é quando mudamos qual nota está no baixo (mais grave). Na posição fundamental, a fundamental está embaixo. Na 1ª inversão, a terça fica no baixo."}], "aula_requisito": 8, "minimo_acertos": 3}'::jsonb, '[]', true, '2025-10-27 21:00:21.599587+00'::timestamptz, '2025-10-27 21:00:21.599587+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

