INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '94f20e7f-6517-4f4c-aada-bf7265187009', $$QUIZ-010$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Teoria Musical Avançada$$, $$Modos, modulação, acordes de 7ª e 9ª. Para quem quer ir além!$$, NULL, 4, 300, 'theoretical', '{"questoes": [{"opcoes": ["Uma escala cromática", "Uma escala com padrão específico de tons", "Um tipo de acorde", "Uma forma musical"], "correta": 1, "pergunta": "O que é um modo musical?", "explicacao": "Modos são escalas com padrões específicos de intervalos. Os 7 modos gregos: Jônio (= escala maior), Dórico, Frígio, Lídio, Mixolídio, Eólio (= menor natural), Lócrio."}, {"opcoes": ["São a mesma coisa", "Modulação muda de tom dentro da música, transposição muda a música toda", "Transposição é só para piano", "Modulação é mais difícil"], "correta": 1, "pergunta": "Qual é a diferença entre modulação e transposição?", "explicacao": "Modulação = mudar de tonalidade DURANTE a música (ex: de Dó Maior para Sol Maior no meio). Transposição = tocar a música INTEIRA em outra tonalidade."}, {"opcoes": ["Acorde do 7º grau", "Acorde do 5º grau com 7ª menor", "Acorde com 7 notas", "Acorde difícil"], "correta": 1, "pergunta": "O que é um acorde de 7ª dominante?", "explicacao": "Acorde de 7ª dominante = acorde do V grau (dominante) + 7ª menor. Em Dó: G7 (Sol-Si-Ré-Fá). Tem tensão que \"pede\" resolução para a tônica. Muito usado no blues e jazz."}, {"opcoes": ["3 notas", "4 notas", "5 notas", "9 notas"], "correta": 2, "pergunta": "Quantas notas tem um acorde de 9ª?", "explicacao": "Acorde de 9ª tem 5 notas: fundamental, 3ª, 5ª, 7ª e 9ª. A 9ª é a 2ª oitavada. Exemplo: C9 = Dó-Mi-Sol-Si♭-Ré. Comum no jazz, bossa nova e música sofisticada."}, {"opcoes": ["Música harmônica", "Notas diferentes com mesmo som", "Acorde complexo", "Instrumento antigo"], "correta": 1, "pergunta": "O que significa \"enarmônico\"?", "explicacao": "Enarmônico = notas escritas diferente mas com MESMO som. Exemplo: Dó# e Ré♭ soam igual no piano. Fá# e Sol♭ também. A escolha depende do contexto harmônico."}], "aula_requisito": 25, "minimo_acertos": 3}'::jsonb, '[]', true, '2025-10-28 01:00:50.854504+00'::timestamptz, '2025-10-28 01:00:50.854504+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

