INSERT INTO core.challenges (tenant_id, id, code, methodology_id, title, description, objectives, difficulty, base_points, challenge_type, evaluation_criteria, required_resources, is_active, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'def6b957-c43f-485d-b623-d39dcb128015', $$QUIZ-002$$, 'a5a5b85d-bace-4415-90bb-01c80cb1564c', $$Leitura de Partitura Nível 1$$, $$Identifique notas na pauta e reconheça valores rítmicos.$$, $$Ler notas na clave de sol; Reconhecer valores rítmicos; Identificar pausas$$, 2, 150, 'practical', '{"questoes": [{"opcoes": ["Mi", "Sol", "Si", "Ré"], "correta": 2, "pergunta": "Qual nota está na segunda linha da clave de sol?", "explicacao": "Na clave de sol, as linhas de baixo para cima são: Mi, Sol, Si, Ré, Fá. Então a segunda linha é o Sol. Os espaços são: Fá, Lá, Dó, Mi."}, {"opcoes": ["1", "1/2", "1/4", "2"], "correta": 1, "pergunta": "Uma colcheia vale quantos tempos?", "explicacao": "A colcheia vale 1/2 tempo (meio tempo). São necessárias 2 colcheias para completar 1 tempo. É metade do valor da semínima."}, {"opcoes": ["Uma linha no espaço", "Um traço na linha", "Um gancho para baixo", "Um quadrado preenchido"], "correta": 2, "pergunta": "Qual é o símbolo da pausa de semínima?", "explicacao": "A pausa de semínima é representada por um pequeno gancho para baixo (ʃ). Ela indica um silêncio de 1 tempo."}], "aula_requisito": 2, "minimo_acertos": 2}'::jsonb, '[]', true, '2025-10-27 21:00:21.599587+00'::timestamptz, '2025-10-27 21:00:21.599587+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

